 \ " &lt;&lt; endl;&#125;int main(int argc, char const *argv[]) &#123; ElementType i = 0; AvlTree pTree = NULL; AvlTree tmp = NULL; UseageHelp(); while (1) &#123; switch (getchar()) &#123; case '1': pTree = MakeEmpty(pTree); cout &lt;&lt; "创建成功 Tree:" &lt;&lt; pTree &lt;&lt; endl; break; case '2': cout &lt;&lt; "请输入插入元素:"; cin &gt;&gt; i; pTree = Insert(i, pTree); cout &lt;&lt; endl; break; case '3': cout &lt;&lt; "请输入删除元素:"; cin &gt;&gt; i; Delete(i, pTree); cout &lt;&lt; endl; break; case '4': tmp = FindMax(pTree); if (tmp != nullptr) &#123; cout &lt;&lt; "最大元素：" &lt;&lt; tmp-&gt;Element &lt;&lt; endl; &#125; cout &lt;&lt; endl; break; case '5': tmp = FindMin(pTree); if (tmp != nullptr) &#123; cout &lt;&lt; "最小元素：" &lt;&lt; tmp-&gt;Element &lt;&lt; endl; &#125; cout &lt;&lt; endl; break; case '6': DrawTree(pTree); cout &lt;&lt; endl; break; case 'h': UseageHelp(); break; case 'q': exit(0); break; default: break; &#125; &#125; return 0;&#125; bantree.h 12345678910111213141516171819202122232425262728293031#ifndef _BANTREE_H#define _BANTREE_H#define ElementType intstruct AvlNode;typedef struct AvlNode *Position;typedef struct AvlNode *AvlTree;AvlTree MakeEmpty(AvlTree T);void DrawTree(AvlTree BT);Position Find(ElementType X, AvlTree T);Position FindMin(AvlTree T);Position FindMax(AvlTree T);AvlTree Insert(ElementType X, AvlTree T);AvlTree Delete(ElementType X, AvlTree T);ElementType Retrieve(Position P);Position SingleRotateWithLeft(Position K2);Position SingleRotateWithRight(Position K2);Position DoubleRotateWithLeft(Position K3);Position DoubleRotateWithRight(Position K3);struct AvlNode &#123; ElementType Element; AvlTree Left; AvlTree Right; int Height;&#125;;#endif bantree.cpp #include "bantree.h"#include &lt;cmath&gt;#include &lt;iostream&gt;#include &lt;queue&gt;#include &lt;stack&gt;#include &lt;string&gt;using namespace std;AvlTree MakeEmpty(AvlTree T) &#123; if (T != nullptr) &#123; MakeEmpty(T-&gt;Left); MakeEmpty(T-&gt;Right); delete T; &#125; return NULL;&#125;static int Height(Position P) &#123; if (P == nullptr) &#123; return -1; &#125; else &#123; return P-&gt;Height; &#125;&#125;/** * description 输出二叉树的高度 * @param[in] BinTree_t * @retval int **/static int FindTreeHeight(AvlTree BT) &#123; int rightlen, leftlen, maxlen; if (BT) &#123; rightlen = FindTreeHeight(BT-&gt;Right); leftlen = FindTreeHeight(BT-&gt;Left); maxlen = leftlen &gt; rightlen ? leftlen : rightlen; return maxlen + 1; &#125; else &#123; return 0; &#125;&#125;/** * @brief 用于清空队列元素 * @param[in] * @param[out] * @return **/static void ClearQueue(queue&lt;AvlTree&gt; &amp;q) &#123; queue&lt;AvlTree&gt; empty; swap(empty, q);&#125;/** * @brief 简单的绘制二叉树图像 * @param[in] * @param[out] * @return **/void DrawTree(AvlTree BT) &#123; int height = FindTreeHeight(BT); int cnt = 0; /* 开始层序遍历二叉树并且绘制图形 */ queue&lt;AvlTree&gt; CurLevelqueue; /*记录当前层的元素 */ queue&lt;AvlTree&gt; NextLevelqueue; /*记录下一层的元素 */ queue&lt;AvlTree&gt; CurTempqueue; /*当前队列副本 */ queue&lt;AvlTree&gt; NextTempqueue; /*下一层队列副本 */ AvlTree temp, lasttemp = NULL; int width = 0; CurLevelqueue.push(BT); //将头节点入队 /*现在修改了入队函数,空指针也可以入队 所以在出队的时候就需要进行判断 */ for (int i = 0; i &lt; height; i++) &#123; cnt = (int)pow(2, i); //当前行的个数21 width = pow(2, height - i + 1); //设置宽度为2^(height-i+1) CurTempqueue = CurLevelqueue; /* 临时记录 */ while (cnt--) &#123; temp = CurLevelqueue.front(); if (temp != NULL) &#123; printf("%*d%*c", width, temp-&gt;Element, width, ' '); NextLevelqueue.push(temp-&gt;Left); NextLevelqueue.push(temp-&gt;Right); //将下一层子节点入队 &#125; else &#123; printf("%*c%*c", width, ' ', width, ' '); NextLevelqueue.push(nullptr); NextLevelqueue.push(nullptr); //如果此层是空，那么再入两个空指针 &#125; CurLevelqueue.pop(); //将上一层节点出队 &#125; printf("
"); NextTempqueue = NextLevelqueue; /* 记录下一层元素 */ /* 接下来打印层间符号 */ if (i != height - 1) &#123; /* 若不是最后一行 */ /* 先记录下一行元素宽度间隔 */ int nextwidth = (int)pow(2, height - i); // /* 按当前层元素位置打印'+' */ // for (int J = 0; J &lt; (int)pow(2, i); J++) &#123; // /* 如果不是最后一行且为null指针 不打印 */ // if (CurTempqueue.front() != nullptr) &#123; // printf("%*c%*c", width, '+', width, ' '); // &#125; else &#123; // printf("%*c%*c", width, ' ', width, ' '); // &#125; // CurTempqueue.pop(); // &#125; // printf("
"); /* 并且以他下一层元素的个数打印'-' */ for (int k = 0; k &lt; (int)pow(2, i + 1); k++) &#123; /* 每隔一位去打印width个'-' */ if ((k % 2) == 0) &#123; /* 偶数位打印 空格+`-` */ if (NextTempqueue.front() != nullptr) &#123; printf("%*c", nextwidth, '-'); for (uint8_t z = 0; z &lt; nextwidth; z++) &#123; printf("-"); &#125; &#125; else &#123; printf("%*c", nextwidth, ' '); for (uint8_t z = 0; z &lt; nextwidth; z++) &#123; printf(" "); &#125; &#125; NextTempqueue.pop(); &#125; else &#123; /* 奇数位打印 空格+`-` */ if (NextTempqueue.front() != nullptr) &#123; for (uint8_t z = 0; z &lt; nextwidth; z++) &#123; printf("-"); &#125; printf("%*c", nextwidth, ' '); &#125; else &#123; for (uint8_t z = 0; z &lt; nextwidth; z++) &#123; printf(" "); &#125; printf("%*c", nextwidth, ' '); &#125; NextTempqueue.pop(); &#125; &#125; printf("
"); &#125; printf(""); swap(CurLevelqueue, NextLevelqueue); /* 交换队列 */ &#125;&#125;Position Find(ElementType X, AvlTree T) &#123; if (T == nullptr) &#123; return nullptr; &#125; if (X &lt; T-&gt;Element) &#123; return Find(X, T-&gt;Left); &#125; else if (X &gt; T-&gt;Element) &#123; return Find(X, T-&gt;Right); &#125; else &#123; return T; &#125;&#125;Position FindMin(AvlTree T) &#123; if (T == nullptr) &#123; return nullptr; &#125; if (T-&gt;Left != nullptr) &#123; return FindMin(T-&gt;Left); &#125; else &#123; return T; &#125;&#125;Position FindMax(AvlTree T) &#123; if (T == nullptr) &#123; return nullptr; &#125; if (T-&gt;Right != nullptr) &#123; return FindMin(T-&gt;Right); &#125; else &#123; return T; &#125;&#125;/** * @brief 平衡树的插入，需要记录每个节点的高度,并实现旋转 * @param[in] * @param[out] * @return **/AvlTree Insert(ElementType X, AvlTree T) &#123; if (T == nullptr) &#123; T = new AvlNode; if (T == nullptr) &#123; std::cout &lt;&lt; "no mem!" &lt;&lt; std::endl; &#125; else &#123; T-&gt;Element = X, T-&gt;Height = 0; T-&gt;Left = T-&gt;Right = nullptr; &#125; &#125; else if (X &lt; T-&gt;Element) &#123; T-&gt;Left = Insert(X, T-&gt;Left); if ((Height(T-&gt;Left) - Height(T-&gt;Right)) == 2) &#123; if (X &lt; T-&gt;Left-&gt;Element) &#123; /* new node in left's left */ T = SingleRotateWithLeft(T); &#125; else &#123; /* new node in left's right */ T = DoubleRotateWithLeft(T); &#125; &#125; &#125; else if (X &gt; T-&gt;Element) &#123; T-&gt;Right = Insert(X, T-&gt;Right); if ((Height(T-&gt;Right) - Height(T-&gt;Left)) == 2) &#123; if (X &gt; T-&gt;Right-&gt;Element) &#123; /* new node in right's right */ T = SingleRotateWithRight(T); &#125; else &#123; /* new node in right's left */ T = DoubleRotateWithRight(T); &#125; &#125; &#125; T-&gt;Height = max(Height(T-&gt;Left), Height(T-&gt;Right)) + 1; return T;&#125;AvlTree Delete(ElementType X, AvlTree T) &#123; Position tmpCell; if (T == nullptr) &#123; std::cout &lt;&lt; "error" &lt;&lt; std::endl; return nullptr; &#125; else if (X &lt; T-&gt;Element) &#123; T-&gt;Left = Delete(X, T-&gt;Left); &#125; else if (X &gt; T-&gt;Element) &#123; T-&gt;Right = Delete(X, T-&gt;Right); &#125; else if (T-&gt;Left &amp;&amp; T-&gt;Right) &#123; tmpCell = FindMin(T-&gt;Right); T-&gt;Element = tmpCell-&gt;Element; T-&gt;Right = Delete(tmpCell-&gt;Element, T-&gt;Right); &#125; else &#123; tmpCell = T; if (T-&gt;Left == nullptr) &#123; T = T-&gt;Right; &#125; else if (T-&gt;Right == nullptr) &#123; T = T-&gt;Right; &#125; delete tmpCell; &#125;&#125;ElementType Retrieve(Position P) &#123;&#125;/*** @brief 单左旋转 当“麻烦节点”在“被发现者”的左子树的左边时，被称为LL插入 需要对 '被发现者' RL旋转（左单旋）**/Position SingleRotateWithLeft(Position K2) &#123; Position K1; K1 = K2-&gt;Left; K2-&gt;Left = K1-&gt;Right; K1-&gt;Right = K2; K2-&gt;Height = max(Height(K2-&gt;Left), Height(K2-&gt;Right)) + 1; K1-&gt;Height = max(Height(K1-&gt;Left), K2-&gt;Height) + 1; return K1; /* 新的根 */&#125;/*** @brief 单右旋转 当“麻烦节点”在“被发现者”的右子树的右边时，被称为RR插入 需要对 '被发现者' RR旋转（右单旋）**/Position SingleRotateWithRight(Position K2) &#123; Position K1; K1 = K2-&gt;Right; K2-&gt;Right = K1-&gt;Left; K1-&gt;Left = K2; K2-&gt;Height = max(Height(K2-&gt;Left), Height(K2-&gt;Right)) + 1; K1-&gt;Height = max(Height(K1-&gt;Left), K2-&gt;Height) + 1; return K1; /* 新的根 */&#125;Position DoubleRotateWithLeft(Position K3) &#123; /* first rotate the k3'left */ K3-&gt;Left = SingleRotateWithRight(K3-&gt;Left); return SingleRotateWithLeft(K3);&#125;Position DoubleRotateWithRight(Position K3) &#123; /* first rotate the k3'right */ K3-&gt;Right = SingleRotateWithLeft(K3-&gt;Right); return SingleRotateWithRight(K3);&#125; Makefile 1234567891011121314151617181920CC = g++CFLAGS = #-g CLIBS = #-lpthread INCLUDE = $(wildcard ./*.h) # INCLUDE = a.h b.h ... can't be defined like "INCLUDE = ./*.h"SOURCES = $(wildcard ./*.cpp) TARGET = avltreeOBJECTS = $(patsubst %.cpp,%.o,$(SOURCES)) $(TARGET) : $(OBJECTS) $(CC) $(CFLAGS) $^ -o $@ $(CLIBS) rm -rf *.o$(OBJECTS) : %.o : %.cpp $(CC) -c $(CFLAGS) $&lt; -o $@ .PHONY : cleanclean: rm -rf *.o $(TARGET) 测试命令 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758➜ balanceTree cat test.txt12322332312362382202242942582126q➜ balanceTree make &amp;&amp; cat test.txt | ./avltreeg++ -c main.cpp -o main.og++ -c bantree.cpp -o bantree.og++ main.o bantree.o -o avltreerm -rf *.o AVL树的操作 (1).创建新的AVL树; (2).插入元素; (3).删除元素; (4).寻找最大元素; (5).寻找最小元素; (6).绘制二叉树; (h).帮助; (q).quit;创建成功 Tree:0请输入插入元素:请输入插入元素:请输入插入元素:请输入插入元素:请输入插入元素:请输入插入元素:请输入插入元素:请输入插入元素:请输入插入元素:请输入插入元素: 32 --------------------------------- 24 36 ----------------- ----------------- 20 31 33 58 ----- --------- 12 38 94

